var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그래서, 본인이 멋대로 계약을 맺었으니 회사더러 출격해 달라.","JPN":"それで、自分が勝手に契約を結んだから、会社に出撃してほしい。","ENG":"So you agreed to a deal on a whim and you want the company's support...","TWN":"所以，妳自己擅自簽了個契約，然後就要求公司出擊。"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그런 말인가요?","JPN":"ということですか？","ENG":"Is that what you're saying?","TWN":"是這個意思嗎？"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그...... 여러 가지 복잡한 사정들이 있지만......","JPN":"その……いろいろと複雑な事情はあるけど……","ENG":"I mean... There's a lot of complex factors involved..","TWN":"這……雖然其中有很多複雜的情況……"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"요약하면...... 맞아.","JPN":"まとめると……その通りだよ。","ENG":"But that's the gist of it... Yeah.","TWN":"但簡單來說……是這樣沒錯。"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하아.......","JPN":"はあ……","ENG":"*Sigh*","TWN":"唉……"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"신입 교육에 소홀하다 싶었더니 결국 이런 문제가 터지는군요.","JPN":"新人研修が手薄だと思ってたら、案の定こんな問題が起こるなんて。","ENG":"I knew rookie training was too lax... Now it's come to bite me in the ass.","TWN":"我才說我們疏忽了對新人的教育，結果就搞出了這種問題。"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이봐요, 미나 양.","JPN":"あのね、ミナさん。","ENG":"Look, Mina.","TWN":"喂，米娜小姐。"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"입사하자마자 휴가 쓰고 놀러 다니는 거야, 잘 몰라서 그렇다고 할 수도 있습니다.","JPN":"入社してすぐに休暇を取って遊ぶのは、まだわかってないから仕方がありません。","ENG":"When you took leave as soon as you were hired, I thought you just didn't know any better.","TWN":"妳剛進公司，就馬上休假出去玩了，所以對這些事可能不太清楚吧。"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하지만 회사 이름을 멋대로 팔고 다녀요?","JPN":"けれど会社の名前をむやみに出すなんて。","ENG":"But how dare you use the company's name like it's your own?","TWN":"但妳怎麼可以一下就出賣了公司的名號呢？"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"사고를 쳐도 정도라는 게 있습니다.","JPN":"とんでもないことをしてくれたわね。","ENG":"You're at the limit of my good graces.","TWN":"即使要闖禍，也該有個限度。"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"게다가 다른 상대도 아니고 CIA라니......","JPN":"しかも、他でもなく、CIAだなんて……","ENG":"And why does it have to be the CIA of all people...","TWN":"而且對象不是別人，偏偏是CIA……"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"미나 양은 아직 업계 경력이 짧아 잘 모르겠지만, 이 바닥에서 정보부 놈들이란 상종하면 신세 망치기 딱 좋은 재해, 역병, 파랑새 같은 겁니다.","JPN":"ミナさんはまだ業界歴が短いのでわかってないと思いますが、この業界で情報局員とは、遭遇すると身を滅ぼしてしまう災害や疫病神、青い鳥のようなものです。","ENG":"You might not know this since you're new, but working with spooks like that is career suicide in this line of work.","TWN":"米娜小姐的就業經歷比較淺，所以可能不太清楚。但是在這個圈子裡，如果和情報部的那些傢伙們打交道，就等於是碰到災難、瘟疫、烏鴉。"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그놈들이랑 엮이면 대체 일이 얼마나 귀찮아지는지 알긴 아는 건가요?","JPN":"そいつらに絡まれたら、いったいどれだけ面倒なことになるかおわかりですか？","ENG":"Do you have any idea how troublesome it is to get involved with them?","TWN":"妳知道和那些傢伙牽扯在一起會有多麻煩嗎！？"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아니, 그게 이쪽도 나름대로 깊이 생각해서.......","JPN":"いや、それはこっちもそれなりに深く考えた結果……","ENG":"But they also put a lot of thought into this as well...","TWN":"不，這我也有自己深思熟慮過……"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"잠깐.","JPN":"ちょっといいかい。","ENG":"Wait.","TWN":"等一下。"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"여기선 내가 얘기하는 게 빠르겠군.","JPN":"ここは私から話すのが早そうだ。","ENG":"I'd better take it from here.","TWN":"這裡讓我來說會比較快吧。"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......그쪽은 누구시죠?","JPN":"……どちら様でしょうか？","ENG":"...And who are you?","TWN":"……在那邊的是誰？"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"댁네 사원에게 일을 부탁한 재해, 역병, 파랑새 같은 의뢰인이지.","JPN":"お宅の社員に仕事を頼んだ、災害、疫病神、青い鳥みたいな依頼人だよ。","ENG":"I'm that suicide-inducing spook that asked your employee for this favor.","TWN":"正是委託貴公司員工幫忙，如同災難、瘟疫、烏鴉般的委託人。"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"중간에 낀 말단 사원을 괴롭히는 것보다는 직접 이야기하는 편이 서로에게 좋지 않겠소?","JPN":"間に挟まれた末端社員をいじめるよりは、直接話したほうがお互いにいいんじゃないか？","ENG":"Don't you think it's best we settle this between us instead of harassing your FNG?","TWN":"比起折磨兩邊都難做人的基層員工，不如我們直接談一談，這樣對彼此不是更好嗎？"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......좋아요.","JPN":"……良いでしょう。","ENG":"...Fine.","TWN":"……那好啊。"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하지만 이 업계에도 룰이라는 게 있습니다.","JPN":"しかし、この業界にもルールというものがあります。","ENG":"But we abide by a certain code of conduct, even in this industry.","TWN":"但是我們這個業界也有自己的規矩。"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"미나 양이 무슨 약속을 했는지는 모르지만 이런 계약은 무효에요.","JPN":"ミナさんがどんな約束をしたかはわかりませんが、このような契約は無効です。","ENG":"I don't know what Mina promised you, but an agreement like that is null and void.","TWN":"我不知道米娜小姐做了什麼承諾，但這種契約是無效的。"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"완전히. 총체적으로. 일말의 여지없이!","JPN":"完全に、一切合切、一考の余地もなく！","ENG":"Completely. Entirely. No exceptions!","TWN":"完全！整個！沒有一絲餘地！"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"......그거 안타깝군.","JPN":"……それは残念だな。","ENG":"Well, isn't that unfortunate.","TWN":"……這還真是可惜。"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"하지만 작전 보수로 이미 선금을 입금했는데, 계약이 무효라면 그건 어떻게 되는 거요?","JPN":"だが、作戦報酬として既に前金を振り込んでいるのに、契約が無効だったらそれはどうなるかな？","ENG":"I've already deposited an advance payment for the mission... What should we do if the agreement is \\"null and void\\"?","TWN":"但是，我方作為作戰報酬的定金已經匯過去了，如果契約無效的話，那該怎麼辦呢？"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"지금 바로 환불해 드리죠. 입금된 계좌로 돌려드리면 되겠죠?","JPN":"今すぐ払い戻しします。振込口座にお返しということで問題ないですわね？","ENG":"I'll give you a refund right away. If whatever checking account you used is even legitimate, that is...","TWN":"我們現在就給您退款吧。就往匯款來的帳戶退回去就可以了吧？"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"마침 저희 회사가 최근에 재정적으로 꽤 안정된 상태라서요.","JPN":"ちょうど弊社は最近、財政的にかなり安定していましてね。","ENG":"It just so happens that our company has been financially stable lately, you see.","TWN":"正好我們公司最近財政上比較穩定。"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이따위 돈 몇 푼으로 저희 회사를 쥐고 흔들겠다는 안이한 생각을 하셨다면 오산.......","JPN":"ちょっとばかしのお金で我が社を牛耳ろうという安易な考えなら、まったくもって見当違い……","ENG":"You're terribly mistaken if you thought you could boss us around with some loose change...","TWN":"如果你覺得用這點錢就能動搖我們公司，那你可就大錯特錯……"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L37_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......응?","JPN":"……え？","ENG":"...Huh?","TWN":"……嗯？"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......어?","JPN":"……ええ？","ENG":"...Huh?","TWN":"……咦？"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"뭐, 뭐야! 이 정신 나간 액수는?!","JPN":"な、何ですか！　このとんでもない金額は！？","ENG":"W-what? You sent us this much money? Are you serious?!","TWN":"什、什麼！這種非常識的金額！？"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"아쉽군.","JPN":"じつに残念だ。","ENG":"It's unfortunate.","TWN":"真是太可惜了。"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"내 30년 경력을 통틀어 봐도 이 정도로 파격적인 제안은 처음인데 말이오.","JPN":"俺の30年間の経歴をひっくるめてみても、こんな破格の提案は初めてなのに。","ENG":"In my 30 years of service, I've never seen the agency make an offer this big.","TWN":"以我30年來的經驗來看，這種破格的金額和提議還是第一次出現呢。"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"거기다 이번 의뢰는 비공식 작전이라 세금 한 푼 떼어가지 않는 순수익일 텐데.......","JPN":"しかも今回の依頼は非公式作戦で、一銭たりとも税金をとられず純収益になるはずなのに……","ENG":"Plus, as this is an unofficial operation, you wouldn't have had to pay a dime in taxes...","TWN":"而且這次委託是非正式作戰，所以這筆錢應該是不扣稅的純收益吧……"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"정말로 아쉽지만...... 업계 룰이라면 어쩔 수 없겠지.","JPN":"実に残念だが、業界のルールなら仕方ないか。","ENG":"Such a shame... But if that's the industry's \\"code of conduct\\", I suppose we have no choice.","TWN":"太遺憾了……但如果是業界規矩的話，那就沒有辦法囉。"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......무슨 말씀이십니까, 고객님?","JPN":"……何をおっしゃいます、お客様。","ENG":"I... believe there's been some misunderstanding, most valued customer.","TWN":"……您這是在說什麼呢，客戶大人？"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"업계 룰 따윈 그냥 참고사항일 뿐이죠.","JPN":"業界ルールなんて、ただの参考事項にすぎません。","ENG":"The code of conduct is merely a guideline!","TWN":"業界規矩不就是參考用的嗎？"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"저희 코핀 컴퍼니는 언제나 고객 만족을 위해 최선을 다할 준비가 되어 있습니다.","JPN":"我がコフィンカンパニーは、常にお客様に満足していただけるよう最善を尽くす準備ができておりますので。","ENG":"The Coffin Company is prepared to serve with our heart and soul to satisfy our clients!","TWN":"我們科芬公司為滿足顧客需求，必定全力以赴，隨時做好萬全的準備！"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"......환불은?","JPN":"……払い戻しは？","ENG":"...What about the refund?","TWN":"……那退款呢？"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"저희 회사에 환불 따윈 없습니다.","JPN":"弊社には払い戻しなんてものはありません。","ENG":"Our company has a no-refund policy.","TWN":"本公司沒有退款服務。"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"낙장불입, 일수불퇴, 복수불반분. 입금된 의뢰는 지옥 끝까지 쫓아가서라도 완수합니다.","JPN":"一手不退。入金済みのご依頼は、地獄の果てまで追いかけてでも必ず果たします。","ENG":"No cancellations. No exchanges. No refunds. Once a payment is received, we'll go to the ends of the earth to fulfill that mission.","TWN":"誠信專業，使命必達。只要是匯款人的委託，即使是追到地獄，我們都會完成到底。"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"다행이군. 합중국은 귀사의 도움을 잊지 않을 거요.","JPN":"それは安心した。合衆国は、御社の協力を忘れないだろう。","ENG":"That's a relief. Uncle Sam will never forget your service.","TWN":"那就好，合眾國不會忘記貴公司的幫助。"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"처음 뵈었을 때부터 남다른 기상이 느껴진다고 생각했는데, 그게 바로 애국심이었군요.","JPN":"初めてお会いした瞬間から並みならぬ印象を受けましたが、それはまさに愛国心の現れだったのすね。","ENG":"I knew there was something uncanny about you the moment we met. You, sir, are a true patriot!","TWN":"第一次見到你們，我就感覺到一種與眾不同的氣質，那就是一顆愛國的心。"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"저희 코핀 컴퍼니는 언제나 팍스 아메리카나에 이바지할 날만 기다리고 있었습니다.","JPN":"コフィンカンパニーは、いつだって、パックス・アメリカーナに貢献する日を心待ちにしておりました。","ENG":"The Coffin Company has been waiting for an opportunity to contribute to Pax Americana.","TWN":"我們科芬公司一直在等待能夠為合眾國做出貢獻的那天。"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......뻔뻔해.","JPN":"……厚かましい。","ENG":"How shameless...","TWN":"……好不要臉。"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"사업이란 걸 하면 사람이 다들 저렇게 바뀌는 걸까?","JPN":"ビジネスになると、みんなあんな風に変わるものなの？","ENG":"Does everyone turn weird when they get into business?","TWN":"做事業的人都會變成那樣嗎？"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그건 잘 모르겠지만 저 사람은 원래부터 저런 사람이었을 거야.","JPN":"それはわからないけど、きっとあれがあの人の素だよ。","ENG":"I'm not sure... but I bet she was always that weird.","TWN":"我不太清楚，但那個人說不定本來就是那樣。"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아마도.......","JPN":"多分ね……","ENG":"Probably...","TWN":"應該吧……"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"뭘 꾸물거리고 있나요?","JPN":"何、もたもたしてるんです？","ENG":"What's taking y'all so long?","TWN":"你們還在拖拖拉拉地幹什麼？"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"당장 집합하세요, 이 밥벌레들!","JPN":"今すぐ集合してください、給料泥棒の皆さん！","ENG":"Report for duty, you good-for-nothing mooches!","TWN":"馬上集合！你們這些飯桶！"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......무슨 일이야, 갑자기.","JPN":"……何なんだ、急に。","ENG":"...What's going on?","TWN":"……幹嘛，這麼突然。"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"한동안 작전은 없다고 푹 쉬라더니?","JPN":"しばらく作戦はないからゆっくり休めと言っていたじゃないか。","ENG":"What ever happened to \\"take it easy, things will be slow for a while?\\"","TWN":"是妳說這一段時間不會有作戰，要我們休息一下的耶？"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하암.......","JPN":"ふあ～。","ENG":"*Yawn*","TWN":"哈啊……"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"부사장님, 오늘 제가 컨디션 난조인 것 같은데 휴가 좀 써도 될까요.","JPN":"副社長、僕は今日体調不良のようなので、お休みをとってもいいですかね。","ENG":"Madame Vice President... I'm not feeling very good. Do you mind if I took sick leave today?","TWN":"副總，我今天狀態好像不是很好，我可以休假嗎？"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"영원한 휴가를 가고 싶지 않다면 입다무세요. 시윤 군.","JPN":"永遠に休みたくなければ、黙ってください。アキヤマ君。","ENG":"Shut your trap if you don't want to go on leave forever. Shiyoon.","TWN":"如果你不想永遠都在休假的話，那就閉嘴，時雲君。"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"조금 전, 이달의 우수 사원께서 회사의 도움을 요청하셨습니다.","JPN":"先ほど今月の優秀社員から協力を求められました。","ENG":"Just a moment ago, our employee of the month asked for our company's assistance.","TWN":"就在剛才，本月的優秀員工向我們公司請求了幫助。"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이에 본사는 전력을 다해 해당 요청을 지원하기로 결정했습니다.","JPN":"そこで本社は全力を尽くしてサポートすることを決定しました。","ENG":"Hence, management decided to commit our every resource to fulfill this request.","TWN":"對此，本公司決定竭盡全力，支援這個請求。"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그러니 당장 출격 준비하세요!","JPN":"ですので、今すぐ出撃準備をしてください！","ENG":"So get ready to move out immediately!","TWN":"所以立刻準備出擊！"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......이 회사에 우수 사원이란 게 있었나?","JPN":"……この会社に優秀社員制度なんてあったか？","ENG":"Since when was there an employee of the month?","TWN":"……這間公司還有優秀員工？"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그럴 리가요. 우수하면 애초에 여길 오지 않겠죠.","JPN":"まさか。優秀なら最初からここには来てませんよ。","ENG":"That's impossible. If they were that good, they wouldn't be here in the first place.","TWN":"就是啊，優秀的話就不會來這裡啦。"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"여러분 같은 밥벌레들과는 다르게 휴가 중에도 언제나 회사를 위해 헌신하는 미나 양께서 월척을......","JPN":"皆さんのような給料泥棒とは違って、休暇中にも会社のために尽くしているミナさんが大物を……","ENG":"Unlike you big mooches, our most dedicated employee Mina diligently worked even during her leave to help us hit the jackpot...","TWN":"和各位這些米蟲不一樣，米娜小姐在休假期間釣到了……"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아니, 계약을 물어왔습니다.","JPN":"いや、契約をとってきました。","ENG":"Uh, I mean, secure a new contract.","TWN":"不，是簽下了一份契約。"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L38_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"내가 잘못 들었나? 누구라고......?","JPN":"聞き間違えか？　誰だって……？","ENG":"Did I hear that right? Who...?","TWN":"是我聽錯了嗎？那是誰啊？"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"저도 확신하긴 어렵지만...... 아마 미나 양이라고 한 것 같은데요......?","JPN":"僕も信じがたいですが、たしかミナさんと言ったような……？","ENG":"I may be mistaken... But I think she said it was Mina...?","TWN":"我也很難相信……但那大概是指米娜小姐吧……?"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......이봐, 이수연.","JPN":"……おい、カナミ。","ENG":"...Hey, Sooyeon.","TWN":"……喂，李秀妍。"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"너 조금 전까지만 해도 신입이 멋대로 휴가계를 내고 사라졌다고 화내고 있었잖아?","JPN":"お前、さっきまでは新人が勝手に休暇届を出して消えたといって、腹を立てていたじゃないか。","ENG":"Weren't you just complaining about the FNG basically going AWOL?","TWN":"妳剛才不是還在生氣，說新人隨便丟了個假單，就消失不見了嗎？"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"돌아오기만 하면 감봉과 시말서 100장 중에 하나를 골라야 할 거라고 벼르지 않았나?","JPN":"帰ったら減給か始末書100枚のうち、どちらかを選ばせると言ってなかったか？","ENG":"You were ready to dock her pay unless she writes a 100-page apology...","TWN":"妳不是說等到她回來，要在減薪和寫100頁悔過書中選一個嗎？"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그야 물론 스승님께서 잘못 들으신 겁니다.","JPN":"それはもちろん、師匠の聞き間違いです。","ENG":"Oh, you must have misheard me.","TWN":"那當然是師父您聽錯了。"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"미나 양 같은 우수사원에게 시말서라니요? 가당치도 않은 일이죠.","JPN":"ミナさんのような優秀社員に始末書だなんて、とんでもない。","ENG":"A written apology? From an outstanding employee like Mina? That's outrageous.","TWN":"讓米娜小姐這樣優秀的人寫悔過書？這一定有什麼誤會。"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"아니, 분명 제대로 들었......","JPN":"いや、間違いなくそう言って……","ENG":"I'm pretty sure I heard you say-","TWN":"不，我聽得很清楚……"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L49_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"소용없습니다, 스승님.","JPN":"師匠、もう無駄ですよ。","ENG":"It's too late, Master.","TWN":"沒用的，師父。"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L50_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"......이미 부사장님 눈이 돈 모양으로 바뀌었어요.","JPN":"……すでに副社長の目はお金の形になっています。","ENG":"I can already see the dollar signs in her eyes.","TWN":"……副總的眼睛已經被錢蒙蔽了。"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L1_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"저 상태의 부사장님께는 어떤 말을 해도 안 들리거든요.","JPN":"あの状態の副社長には、何を言っても聞こえやしません。","ENG":"She won't listen to a word you say right now.","TWN":"這個狀態下，不論妳對副總說什麼，她都聽不進去的啦。"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L3_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"전 언제나 미나 양이 큰일을 해낼 거라고 믿고 있었죠.","JPN":"私はミナさんがいつか大業を成し遂げると信じていました。","ENG":"I always knew Mina would do something incredible.","TWN":"之前，我就一直相信米娜小姐能成大事。"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"제 기대가 틀리지 않았다는 것이 이렇게 증명되었군요.","JPN":"私の期待が間違っていなかったことが、ついに証明されましたね。","ENG":"My intuition has never failed me!","TWN":"事實證明，我的期望果然沒有錯。"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......그나저나 뭘 꾸물대고 있는 거죠? 다들.","JPN":"……ところで、突っ立ってる場合じゃないですよ？　皆さん。","ENG":"Anyway... Why are you still just standing there? Huh?","TWN":"……那你們還在磨蹭什麼？"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"코핀 컴퍼니의 모토는 신속, 정확입니다!","JPN":"コフィンカンパニーのモットーは、スピードと正確性です！","ENG":"The Coffin Company's motto is Speed and Accuracy!","TWN":"我們科芬公司的座右銘——“迅速，準確！”"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"고객님 기다리게 하지 말고, 빨리빨리 출발하세요!","JPN":"お客様を待たせないで、速やかに出発してください！","ENG":"Don't keep the customer waiting. Get out there already!","TWN":"不可以讓客戶久等，立刻出發！"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};